            locale,
            steps: props.steps.clone(),
            current_step: 0,
            total_steps: total,
            target_element_id: props.steps.first().and_then(|s| s.target.clone()),
            focused: false,
            focus_visible: false,
            open,
            ids,
            messages,
        })
    }

