/// State machine for the `Tour` component.
#[derive(Debug)]
pub struct Machine;

impl ars_core::Machine for Machine {
    type State = State;
    type Event = Event;
    type Context = Context;
    type Props = Props;
    type Messages = Messages;
    type Effect = Effect;
    type Api<'a> = Api<'a>;

    fn init(
        props: &Self::Props,
        env: &Env,
        messages: &Self::Messages,
    ) -> (Self::State, Self::Context) {
        let ids = ComponentIds::from_id(&props.id);
        let total_steps = props.steps.len();
        let open = props.open.unwrap_or(props.default_open || props.auto_start) && total_steps > 0;
        let state = if open {
            State::Active { step_index: 0 }
        } else {
            State::Inactive
        };

        (
            state,
            Context {
                locale: env.locale.clone(),
                steps: props.steps.clone(),
                current_step: 0,
                total_steps,
                target_element_id: props.steps.first().and_then(|step| step.target.clone()),
                focused: false,
                focus_visible: false,
                open,
                ids,
                positioning: PositioningOptions::default(),
                current_placement: Placement::Bottom,
                spotlight: None,
                z_index: None,
                messages: messages.clone(),
            },
        )
    }

    fn transition(
        _state: &Self::State,
        _event: &Self::Event,
        _context: &Self::Context,
        _props: &Self::Props,
    ) -> Option<TransitionPlan<Self>> {
        None
    }

    fn connect<'a>(
        state: &'a Self::State,
        ctx: &'a Self::Context,
        props: &'a Self::Props,
        send: &'a dyn Fn(Self::Event),
    ) -> Self::Api<'a> {
        Api {
            state,
            ctx,
            props,
            send,
        }
    }
}

/// Connected API surface for the `Tour` component.
pub struct Api<'a> {
    state: &'a State,
    ctx: &'a Context,
    props: &'a Props,
    send: &'a dyn Fn(Event),
}

impl Api<'_> {
    /// Returns whether the tour is open.
    #[must_use]
    pub const fn is_open(&self) -> bool {
        self.ctx.open
    }

    /// Attributes for the root element.
    #[must_use]
    pub fn root_attrs(&self) -> AttrMap {
        let _ = (self.state, self.props, self.send);
        AttrMap::new()
    }
}

impl ConnectApi for Api<'_> {
    type Part = Part;

    fn part_attrs(&self, _part: Part) -> AttrMap {
        AttrMap::new()
    }
}

